namespace DragonWarsTrainer.Game;

/// <summary>
/// A named, ready-to-write item prototype: the 11-byte slot header (byte 0 flags/charges
/// through byte 10 ammo/range) plus the item name. Values were transcribed from captured
/// Dragon Wars shop/treasure data (<c>.data/DragonWars.ahk</c>) and decoded through the
/// shared high-bit name codec; they are pending live-game confirmation.
/// </summary>
public sealed record ItemTemplate(string Category, string Name, byte[] Header);

/// <summary>
/// Catalog of known Dragon Wars items, grouped by category, used to populate the inventory
/// slot picker. Applying a template writes its header bytes and re-encodes its name into a slot.
/// </summary>
